svg.script:

function generateSpreadPattern(group, centerX, centerY, radius, density, spreadType) {
	const numPoints = density * 10;
	for (let i = 0; i < numPoints; i++) {
		let angle = Math.random() * 2 * Math.PI;
		let distance;
		let x, y;
		if (spreadType === "upper_right_outer") {
			distance = radius / 4 + Math.random() * radius / 4;
			x = centerX + (distance * 1 * Math.cos(angle));
			y = centerY - (distance * 1 * Math.sin(angle));
			if (x < centerX || y > centerY) {
				i--;
				continue;
			}
		} else if (spreadType === "whole") {
			distance = Math.random() * radius;
			x = centerX + distance * Math.cos(angle);
			y = centerY + distance * Math.sin(angle);
		} else if (spreadType === "upper_half") {
			distance = Math.random() * radius;
			x = centerX + distance * Math.cos(angle);
			y = centerY - Math.abs(distance * Math.sin(angle));
		} else if (spreadType === "inner_ring") {
			distance = Math.random() * (radius / 3);
			x = centerX + distance * Math.cos(angle);
			y = centerY + distance * Math.sin(angle);
		} else {
			distance = Math.random() * radius; // default to random
			x = centerX + distance * Math.cos(angle);
			y = centerY + distance * Math.sin(angle);
		}
		group.innerHTML += `&lt;circle cx="${x}" cy="${y}" r="2" fill="blue"/&gt;`;
	}
}

function createTargetPattern(svg, centerX, centerY, radius, density, spreadType, label) {
	const group = document.createElementNS("http://www.w3.org/2000/svg", "g");
	group.setAttribute("transform", `translate(${centerX},${centerY})`);
	svg.appendChild(group);
	for (let r = radius; r > 0; r -= 20) {
		const circle = document.createElementNS("http://www.w3.org/2000/svg", "circle");
		circle.setAttribute("cx", "0");
		circle.setAttribute("cy", "0");
		circle.setAttribute("r", r.toString());
		circle.setAttribute("stroke", "magenta");
		circle.setAttribute("stroke-width", "2");
		circle.setAttribute("fill", "none");
		group.appendChild(circle);
	}
	const innerRedCircle = document.createElementNS("http://www.w3.org/2000/svg", "circle");
	innerRedCircle.setAttribute("cx", "0");
	innerRedCircle.setAttribute("cy", "0");
	innerRedCircle.setAttribute("r", "10");
	innerRedCircle.setAttribute("stroke", "#FF5733");
	innerRedCircle.setAttribute("stroke-width", "2");
	innerRedCircle.setAttribute("fill", "#FF5733");
	group.appendChild(innerRedCircle);

	generateSpreadPattern(group, 0, 0, radius, density, spreadType);
	const text = document.createElementNS("http://www.w3.org/2000/svg", "text");
	text.setAttribute("x", "0");
	text.setAttribute("y", (radius + 30).toString());
	text.setAttribute("font-family", "Calibri");
	text.setAttribute("font-size", "30");
	text.setAttribute("text-anchor", "middle");
	text.setAttribute("fill", "blue");
	text.setAttribute("font-weight", "bold");
	text.textContent = label;
	group.appendChild(text);
}

document.addEventListener("DOMContentLoaded", function() {
	const svg = document.querySelector("svg");
	createTargetPattern(svg, 100, 100, 90, 5, "upper_right_outer", "1");
	createTargetPattern(svg, 300, 100, 90, 5, "whole", "2");
	createTargetPattern(svg, 500, 100, 90, 5, "upper_half", "3");
	createTargetPattern(svg, 700, 100, 90, 5, "inner_ring", "4");
});
